{"content":"use crate::api::*;
use crate::distance::l2_distance;
use rayon::prelude::*;
use parking_lot::RwLock;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

pub struct VectorDB {
    data: RwLock<Vec<(u64, Vec<f32>)>>,
}

#[derive(PartialEq)]
struct OrderedSearchResult {
    id: u64,
    distance: f64,
}

impl OrderedSearchResult {
    fn new(id: u64, distance: f64) -> Self {
        Self { id, distance }
    }
}

// We want a Max-Heap to keep track of the smallest k elements.
// The standard PartialOrd for f64 doesn't exist, so we have to implement Ord for our wrapper.
// Also, we want the "largest" element in the heap to be the one with the largest distance,
// so when we pop, we remove the worst candidate.
impl Eq for OrderedSearchResult {}

impl PartialOrd for OrderedSearchResult {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        self.distance.partial_cmp(&other.distance)
    }
}

impl Ord for OrderedSearchResult {
    fn cmp(&self, other: &Self) -> Ordering {
        // Handle NaNs? Assume no NaNs in valid vector data.
        self.distance.partial_cmp(&other.distance).unwrap_or(Ordering::Equal)
    }
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut data = self.data.write();
        data.push((id, vector));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write();
        let count = vectors.len();
        data.extend(vectors);
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        if top_k == 0 {
            return vec![];
        }

        let data = self.data.read();

        // Use Rayon to parallelize the scan
        // We can chunk the data or just use the parallel iterator provided by Rayon.
        // fold/reduce pattern is good here to merge heaps.

        let top_results = data.par_iter()
            .fold(
                || BinaryHeap::with_capacity((top_k + 1) as usize),
                |mut heap, (id, vec)| {
                    let dist = l2_distance(vector, vec);
                    heap.push(OrderedSearchResult::new(*id, dist));
                    if heap.len() > top_k as usize {
                        heap.pop();
                    }
                    heap
                }
            )
            .reduce(
                || BinaryHeap::with_capacity((top_k + 1) as usize),
                |mut heap1, heap2| {
                    for item in heap2 {
                        heap1.push(item);
                        if heap1.len() > top_k as usize {
                            heap1.pop();
                        }
                    }
                    heap1
                }
            );

        // Convert heap to sorted vector (ascending distance)
        let mut results = top_results.into_sorted_vec();
        // into_sorted_vec returns ascending order for a MaxHeap? 
        // "The elements are popped from the heap in order, which is max-first."
        // Wait, standard BinaryHeap is a MaxHeap.
        // pop() gives the largest element.
        // into_sorted_vec() "consumes the BinaryHeap and returns a vector in sorted (ascending) order."
        // Let's verify documentation behavior or just manual sort.
        // To safely get "closest first" (smallest distance):
        // The heap stores the K smallest distances. The top is the largest of those K.
        // so into_sorted_vec() (which is effectively repeated pops) would give largest to smallest?
        // Actually, the docs say: "returns the elements in ascending order".
        // Let's stick to explicit sorting to be sure.

        let mut search_results: Vec<SearchResult> = results.into_iter()
            .map(|r| SearchResult { id: r.id, distance: r.distance })
            .collect();

        // Correctness check: into_sorted_vec() docs say "ascending order" which is exactly what we want 
        // because we implemented Ord based on distance.
        // Wait, if it's a MaxHeap, the "largest" is at the Root. 
        // If we want to keep the "smallest K", the heap must pop the "largest" when full.
        // This is correct: `if heap.len() > top_k { heap.pop(); }` removes the largest distance.
        // So the heap contains the smallest distances.
        // into_sorted_vec returns them in ascending order of the Ord trait.
        // Our Ord is distance. So it should return smallest distance to largest distance.

        search_results
    }
}
