{"content":"use crate::api::*;
use rayon::prelude::*;
use parking_lot::RwLock;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

// Constants
const DIM: usize = 128;

pub struct VectorDB {
    // Structure of Arrays (SoA) layout
    // IDs: one per vector
    // Vectors: flat array, stride = DIM
    ids: RwLock<Vec<u64>>,
    vectors: RwLock<Vec<f32>>,
}

#[derive(PartialEq)]
struct OrderedSearchResult {
    id: u64,
    distance: f32, // Changed to f32 for performance, avoiding casting in hot loop
}

impl Eq for OrderedSearchResult {}

impl PartialOrd for OrderedSearchResult {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        self.distance.partial_cmp(&other.distance)
    }
}

impl Ord for OrderedSearchResult {
    fn cmp(&self, other: &Self) -> Ordering {
        self.distance.partial_cmp(&other.distance).unwrap_or(Ordering::Equal)
    }
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            ids: RwLock::new(Vec::new()),
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != DIM {
            panic!("Vector dimension mismatch");
        }
        let mut ids = self.ids.write();
        let mut vectors = self.vectors.write();
        ids.push(id);
        vectors.extend(vector);
    }

    pub fn bulk_insert(&self, new_vectors: Vec<(u64, Vec<f32>)>) -> usize {
        if new_vectors.is_empty() {
            return 0;
        }
        let count = new_vectors.len();
        let mut ids = self.ids.write();
        let mut vectors = self.vectors.write();

        ids.reserve(count);
        vectors.reserve(count * DIM);

        for (id, vec) in new_vectors {
            if vec.len() != DIM {
                panic!("Vector dimension mismatch");
            }
            ids.push(id);
            vectors.extend(vec);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        if top_k == 0 {
            return vec![];
        }

        // Take read locks
        let ids = self.ids.read();
        let vectors = self.vectors.read();
        let n_vectors = ids.len();

        if n_vectors == 0 {
            return vec![];
        }

        // Rayon chunks
        // Each chunk processes a subset of vectors and returns a local TopK heap.
        // Then we merge the heaps.

        // We calculate squared distances first to avoid sqrt in hot loop?
        // Ah, spec requires actual L2 distance in result. We can sqrt at the very end.
        // But let's check recall first.

        let chunk_size = 1000; // Tunable parameter

        let best_merged = ids.par_chunks(chunk_size)
            .zip(vectors.par_chunks(chunk_size * DIM))
            .map(|(id_chunk, vec_chunk)| {
                let mut heap = BinaryHeap::with_capacity((top_k + 1) as usize);

                for (i, id) in id_chunk.iter().enumerate() {
                    let vec_slice = &vec_chunk[i * DIM .. (i + 1) * DIM];

                    // Inline distance calc or call l2_distance?
                    // Let's use a specialized function for slices.
                    let dist_sq = l2_distsq(query, vec_slice);

                    // We use MaxHeap to keep smallest K. 
                    // To keep smallest K, we push valid candidates. 
                    // If size > K, we pop the largest.
                    heap.push(OrderedSearchResult { id: *id, distance: dist_sq });
                    if heap.len() > top_k as usize {
                        heap.pop();
                    }
                }
                heap
            })
            .reduce(
                || BinaryHeap::with_capacity((top_k + 1) as usize),
                |mut heap1, heap2| {
                    for item in heap2 {
                        heap1.push(item);
                        if heap1.len() > top_k as usize {
                            heap1.pop();
                        }
                    }
                    heap1
                }
            );

        // Convert to sorted vector
        let sorted = best_merged.into_sorted_vec();

        sorted.into_iter().map(|r| SearchResult { 
            id: r.id, 
            distance: r.distance.sqrt() as f64 // sqrt here
        }).collect()
    }
}

// Inline optimized distance squared
#[inline(always)]
fn l2_distsq(a: &[f32], b: &[f32]) -> f32 {
    let mut sum = 0.0;
    for i in 0..DIM {
        let d = a[i] - b[i];
        sum += d * d;
    }
    sum
}
